// ═══════════════════════════════════════════════════════════════
// NORMALIZE & DEDUP — copied verbatim from Job_Application_Automator_v6.json
// To add a new board: add an entry to BOARD_CONFIG, wire the
// Apify node to this Code node, done. Nothing else changes.
// ═══════════════════════════════════════════════════════════════

const BOARD_CONFIG = {
  '2a. Scrape LinkedIn': {
    source: 'LinkedIn',
    fields: {
      id:          'id',
      title:       ['title', 'jobTitle'],
      company:     ['companyName', 'company'],
      location:    'location',
      description: ['descriptionText', 'description'],
      url:         ['link', 'url'],
      applyUrl:    ['applyUrl', 'link'],
      postedAt:    'postedAt',
      salary:      'salary',
      remote:      'workRemoteAllowed',
      seniority:   ['seniorityLevel', 'seniority'],
      country:     'country',
    }
  },
  '2b. Scrape Indeed': {
    source: 'Indeed',
    fields: {
      id:          'key',
      title:       'title',
      company:     'employer.name',
      location:    ['location.formattedLocation', 'location.city'],
      description: 'description.text',
      url:         ['url', 'jobUrl'],
      applyUrl:    ['url', 'jobUrl'],
      postedAt:    'datePublished',
      salary:      null,
      remote:      null,
      seniority:   null,
      country:     'location.countryCode',
    }
  },
  '2c. Scrape StepStone': {
    source: 'StepStone',
    fields: {
      id:          'id',
      title:       'title',
      company:     'company_details.company_name',
      location:    'workplace_details.job_location',
      description: 'content_details.full_description',
      url:         'source.url',
      applyUrl:    'detail_page.applying_details.applying_url',
      postedAt:    'posting_details.published_at',
      salary:      'compensation_details.detail_salary',
      remote:      'workplace_details.work_arrangement',
      seniority:   null,
      country:     null,
    }
  },
  '2d. Scrape Glassdoor': {
    source: 'Glassdoor',
    fields: {
      id:          'key',
      title:       'title',
      company:     ['company.companyName', 'company.name', 'companyName', 'employer_name', 'employer'],
      location:    ['location_city', 'location', 'location_country'],
      description: 'description_text',
      url:         'jobUrl',
      applyUrl:    'applyUrl',
      postedAt:    'datePublished',
      salary:      null,
      remote:      'remoteWorkTypes',
      seniority:   null,
      country:     null,
    }
  },
  '2e. Scrape Xing': {
    source: 'Xing',
    fields: {
      id:          'job_id',
      title:       'title',
      company:     'company',
      location:    'location',
      description: 'description_text',
      url:         'url',
      applyUrl:    'apply_url',
      postedAt:    'date_posted',
      salary:      'salary',
      remote:      'remote',
      seniority:   null,
      country:     'location_country_code',
    }
  },
};

const ALLOWED_COUNTRIES = new Set(['DE', 'AT', 'CH', 'NL', 'BE', '']);

function getNestedValue(obj, path) {
  if (!path) return undefined;
  return path.split('.').reduce((o, k) => (o && o[k] !== undefined) ? o[k] : undefined, obj);
}

function resolveField(obj, mapping) {
  if (mapping === null || mapping === undefined) return '';
  if (Array.isArray(mapping)) {
    for (const path of mapping) {
      const val = getNestedValue(obj, path);
      if (val !== undefined && val !== null && val !== '') return val;
    }
    return '';
  }
  return getNestedValue(obj, mapping) || '';
}

function extractSalary(obj, config) {
  const raw = resolveField(obj, config.fields.salary);
  if (raw && typeof raw === 'string' && raw.length > 0) return raw;
  if (raw && typeof raw === 'object' && raw.min) {
    const { min, max, currency, currencyIso, period } = raw;
    return `${currency || currencyIso || ''} ${min}${max ? `-${max}` : ''}/${period || ''}`.trim();
  }
  if (obj.baseSalary && obj.baseSalary.min) {
    const { min, max, currencyCode, unitOfWork } = obj.baseSalary;
    return `${currencyCode || ''} ${min}-${max}/${unitOfWork || ''}`.trim();
  }
  if (obj.baseSalary_min) {
    const { baseSalary_min: min, baseSalary_max: max, salary_currency: cur, salary_period: period } = obj;
    return `${cur || ''} ${min}${max ? `-${max}` : ''}/${period || ''}`.trim();
  }
  return '';
}

function extractCompanyFromUrl(url) {
  if (!url) return '';
  const glassdoorMatch = String(url).match(/-at-([\w-]+?)-JV_/i);
  if (glassdoorMatch) {
    return glassdoorMatch[1].replace(/-/g, ' ').trim();
  }
  return '';
}

const jobs = [];

for (const [nodeName, config] of Object.entries(BOARD_CONFIG)) {
  let items;
  try {
    items = $(nodeName).all();
  } catch (e) {
    continue;
  }
  if (!items || items.length === 0) continue;

  for (const item of items) {
    const d = item.json;
    if (!d || typeof d !== 'object') continue;

    const desc = String(resolveField(d, config.fields.description));
    if (desc.length < 20) continue;

    const country = String(resolveField(d, config.fields.country) || '').toUpperCase();
    if (country && !ALLOWED_COUNTRIES.has(country)) continue;

    const rawCompany = String(resolveField(d, config.fields.company));
    jobs.push({
      source:      config.source,
      id:          String(resolveField(d, config.fields.id)),
      title:       String(resolveField(d, config.fields.title)),
      company:     rawCompany || extractCompanyFromUrl(resolveField(d, config.fields.url)) || 'Unknown Company',
      location:    String(resolveField(d, config.fields.location)),
      description: desc,
      url:         String(resolveField(d, config.fields.url)),
      applyUrl:    String(resolveField(d, config.fields.applyUrl)),
      postedAt:    String(resolveField(d, config.fields.postedAt)),
      salary:      extractSalary(d, config),
      remote:      !!resolveField(d, config.fields.remote),
      seniority:   String(resolveField(d, config.fields.seniority)),
    });
  }
}

const seen = new Set();
const unique = [];
for (const job of jobs) {
  const key = job.url || job.applyUrl || `${job.company}::${job.title}`;
  if (seen.has(key)) continue;
  seen.add(key);
  unique.push(job);
}

if (unique.length === 0) {
  return [{ json: { error: 'No valid jobs after normalize + dedup. Check Apify outputs and country filter.', rawCount: jobs.length } }];
}

return unique.map(j => ({ json: j }));

const item = $json;

if (item.skipped || item.error) {
  return { json: { ...item, _skip: true } };
}

const systemPrompt = "You are a senior tech-recruiting analyst extracting REQUIRED SKILLS from a single job posting.\n\nReturn ONLY valid JSON. No prose, no markdown.\n\nOutput schema:\n{\n  \"skills\": [\n    { \"name\": \"...\", \"tier\": 1, \"evidence\": \"verbatim phrase from JD\", \"category\": \"language|framework|tool|platform|cloud|database|methodology|soft\" }\n  ]\n}\n\nTIER DEFINITIONS:\n- Tier 1 (Core): The most common / must-have skills for this role family - listed under explicit hard requirements (\"required\", \"must have\", \"expert in\", \"strong knowledge of\"), or skills mentioned multiple times across the JD.\n- Tier 2 (Strong): Less common but clearly valuable - listed under \"nice to have\", \"plus\", \"preferred\", \"wuenschenswert\", \"von Vorteil\", or mentioned once but tied to a major responsibility.\n- Tier 3 (Edge): Rare differentiator - niche tools, certifications, domain-specific terms, or skills mentioned only in passing that signal sophistication.\n\nEXTRACTION RULES:\n- Normalize names: \"ReactJS\" -> \"React\", \"AWS Cloud\" -> \"AWS\", \"K8s\" -> \"Kubernetes\", \"Node\" -> \"Node.js\", \"TypeScript (TS)\" -> \"TypeScript\".\n- One entry per distinct skill. Do NOT duplicate.\n- Skip generic adjectives (\"strong\", \"good\", \"experienced\"); skip company names, benefits, perks, salary.\n- Skip pure soft skills (\"team player\", \"motivated\") UNLESS they are explicitly central to the role - in which case put them in Tier 3.\n- evidence MUST be a verbatim phrase (<=120 chars) from the JD that triggered the inference. If the JD is in German, evidence stays German.\n- Cap at 25 skills total per job. Prefer fewer high-quality entries over noise.\n- If JD is too short or empty, return { \"skills\": [] }.";

const jd = (item.description || '').replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();

const userMsg = [
  'JOB:' ,
  'Title: ' + (item.title || ''),
  'Company: ' + (item.company || ''),
  'Location: ' + (item.location || ''),
  '',
  'JOB DESCRIPTION:',
  jd
].join('\n');

return {
  json: {
    ...item,
    _openAISkillBody: {
      model: $('1. Manual Configuration').first().json.skillExtractionModel || 'gpt-5.4-nano',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userMsg }
      ],
      temperature: 0.2,
      response_format: { type: 'json_object' }
    }
  }
};

const aiResponse = $json;
const jobData = $('7. Build Skill Extraction Prompt').item.json;
const { _openAISkillBody, ...cleanJob } = jobData;

if (cleanJob._skip) {
  return { json: { ...cleanJob, skills_extracted: [], _extractError: false } };
}

let skills = [];
let extractError = false;
let errorMsg = '';

try {
  if (aiResponse.error) {
    extractError = true;
    errorMsg = 'OpenAI API error: ' + (aiResponse.error.message || 'unknown');
  } else {
    const content = aiResponse.choices && aiResponse.choices[0] && aiResponse.choices[0].message && aiResponse.choices[0].message.content;
    if (!content) throw new Error('No content in OpenAI response');
    const parsed = JSON.parse(content);
    skills = (parsed.skills || [])
      .map(s => ({
        name: String(s.name || '').trim(),
        tier: Number(s.tier) || 3,
        evidence: String(s.evidence || '').slice(0, 200),
        category: String(s.category || 'tool')
      }))
      .filter(s => s.name.length > 1 && [1, 2, 3].includes(s.tier));
  }
} catch (err) {
  extractError = true;
  errorMsg = 'Parse error: ' + err.message;
}

return {
  json: {
    title: cleanJob.title,
    company: cleanJob.company,
    location: cleanJob.location,
    url: cleanJob.url,
    source: cleanJob.source,
    skills_extracted: skills,
    _extractError: extractError,
    _extractErrorMsg: errorMsg
  }
};

// The Split in Batches done output contains all parsed skill items.
const allItems = $input.all();

const TIER_WEIGHT = { 1: 3, 2: 2, 3: 1 };
const skillStats = {};

let jobsWithSkills = 0;
let jobsErrored = 0;

for (const it of allItems) {
  const data = it.json;
  if (data._extractError) jobsErrored += 1;
  if (!Array.isArray(data.skills_extracted) || data.skills_extracted.length === 0) continue;
  jobsWithSkills += 1;

  for (const sk of data.skills_extracted) {
    const key = sk.name.toLowerCase().trim();
    if (!skillStats[key]) {
      skillStats[key] = {
        name: sk.name,
        count: 0,
        weighted: 0,
        tiers: { 1: 0, 2: 0, 3: 0 },
        category: sk.category,
        job_titles: new Set(),
        sample_evidence: []
      };
    }
    const e = skillStats[key];
    e.count += 1;
    e.weighted += TIER_WEIGHT[sk.tier] || 1;
    e.tiers[sk.tier] = (e.tiers[sk.tier] || 0) + 1;
    if (data.title) e.job_titles.add(data.title);
    if (e.sample_evidence.length < 3 && sk.evidence) e.sample_evidence.push(sk.evidence);
  }
}

const ranked = Object.values(skillStats)
  .map(e => {
    const t1 = e.tiers[1], t2 = e.tiers[2], t3 = e.tiers[3];
    const dominantTier = (t1 >= t2 && t1 >= t3) ? 1 : (t2 >= t3 ? 2 : 3);
    return {
      ...e,
      job_titles: Array.from(e.job_titles),
      dominantTier
    };
  })
  .sort((a, b) => b.weighted - a.weighted || b.count - a.count);

const top10 = ranked.slice(0, 10);

const tierBuckets = { 1: [], 2: [], 3: [] };
for (const r of ranked) {
  if (tierBuckets[r.dominantTier].length < 8) {
    tierBuckets[r.dominantTier].push({
      name: r.name,
      count: r.count,
      weighted: r.weighted,
      sample_titles: r.job_titles.slice(0, 5)
    });
  }
}

return [{
  json: {
    total_jobs_analyzed: jobsWithSkills,
    total_jobs_errored: jobsErrored,
    total_skills_unique: ranked.length,
    top10,
    tierBuckets,
    fullRanking: ranked.slice(0, 40)
  }
}];

const agg = $json;
const resumeItem = $('5. GET Resume Context').first();
const resume = (resumeItem && resumeItem.json && !resumeItem.json.error) ? resumeItem.json : {};

const systemPrompt = `You are a senior tech career strategist for a Salesforce / Software Developer based in Germany.

You will receive (1) the most in-demand skills extracted from a real batch of fresh job postings, ranked by frequency and tier weight, and (2) the candidate's base resume. Produce an actionable upskilling report.

Return ONLY valid JSON in this EXACT shape (no prose outside the JSON):

{
  "top10_recommendations": [
    {
      "skill": "name as it appears in the demand list",
      "why_it_matters": "1-2 sentence justification grounded in the demand data",
      "how_to_acquire": "CONCRETE plan: name actual courses, certifications, or projects. Include rough time/cost where possible."
    }
  ],
  "tier_summaries": {
    "tier1": "1-2 sentence summary describing what kind of must-have skills appear in Tier 1 and which job-title clusters require them",
    "tier2": "1-2 sentence summary of strong-but-less-common Tier 2 skills and example titles",
    "tier3": "1-2 sentence summary of edge / differentiator Tier 3 skills and example titles"
  },
  "skills_i_have": [ "matching skill names from the demand list" ],
  "skills_im_missing": [ "skill names from the demand list NOT covered by the resume" ],
  "gap_closing_plan": [
    {
      "skill": "...",
      "priority": "high",
      "reason": "market demand × tier rationale (e.g. 'count=12, dominant tier 1 — top-3 skill in the batch')",
      "first_step": "the single concrete action to take this week (be specific)"
    }
  ]
}

PRIORITIZATION FOR gap_closing_plan: order by (market frequency × tier weight). 'high' = appears in top 10 missing and dominant tier ≤ 2. 'medium' = appears top 11–25 OR tier 2/3 but high frequency. 'low' = niche differentiator.

For how_to_acquire and first_step, be SPECIFIC. Vague advice is worthless. Examples of GOOD answers:
- "AWS Solutions Architect Associate certification (3-4 weeks self-study, ~$150 exam, use Adrian Cantrill's course)"
- "Build a CRUD app with Next.js App Router + Prisma + Postgres, deploy to Vercel — commit weekly to GitHub"
- "Coursera 'Deep Learning Specialization' by Andrew Ng + reproduce 1 paper from Papers With Code"
- "Trailhead Salesforce Data Cloud Specialist superbadge + Data Cloud Consultant cert (~$200)"

Do NOT recommend a skill the candidate already has. Do NOT invent skills not in the demand list.`;

const skillsList = (resume.currentSkills || []).flatMap(c => {
  const details = (c.details || c.infoHtml || '').replace(/<[^>]+>/g, '');
  return [c.skill, ...details.split(/[,;|]/)];
}).map(s => (s || '').trim()).filter(Boolean);

const workSummary = (resume.currentWork || []).slice(0, 3).map(w =>
  `- ${w.jobTitle || ''} at ${w.employer || ''}: ${(w.description || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').slice(0, 250)}`
).join('\n');

const projectSummary = (resume.currentProjects || []).slice(0, 6).map(p =>
  `- ${p.name || ''} (${p.techStack || 'n/a'})`
).join('\n');

const topLines = agg.top10.map((s, i) =>
  `${i + 1}. ${s.name} — count=${s.count}, weighted=${s.weighted}, T1=${s.tiers[1]} T2=${s.tiers[2]} T3=${s.tiers[3]}, sample titles: ${(s.job_titles || []).slice(0, 3).join(' | ')}`
).join('\n');

const fullLines = agg.fullRanking.map(s =>
  `- ${s.name} (count=${s.count}, weighted=${s.weighted}, dominantTier=${s.dominantTier}, category=${s.category || 'n/a'})`
).join('\n');

const userMsg = `MARKET DEMAND SUMMARY (${agg.total_jobs_analyzed} jobs analyzed)

TOP 10 SKILLS BY WEIGHTED FREQUENCY:
${topLines}

FULL RANKING (top 40):
${fullLines}

=========================
CANDIDATE RESUME
=========================
Title: ${resume.currentJobTitle || 'Software Developer'}
Profile (raw): ${(resume.currentProfile || '').replace(/<[^>]+>/g, ' ').slice(0, 400)}

Skills already on resume:
${skillsList.join(', ')}

Recent Work:
${workSummary || '(none)'}

Projects:
${projectSummary || '(none)'}

Now produce the JSON report described in the system instructions.`;

return {
  json: {
    ...agg,
    _resumePresent: Object.keys(resume).length > 0,
    _openAIBody: {
      model: $('1. Manual Configuration').first().json.openaiModel || 'gpt-5.4-mini',
      temperature: 0.4,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userMsg }
      ]
    }
  }
};

const ai = $json;
const agg = $('12. Build Final Analysis Prompt').first().json;
const cfg = $('1. Manual Configuration').first().json;

let report = null;
let parseError = '';
try {
  const content = ai.choices && ai.choices[0] && ai.choices[0].message && ai.choices[0].message.content;
  if (!content) throw new Error('No content in OpenAI response');
  report = JSON.parse(content);
} catch (e) {
  parseError = 'Failed to parse OpenAI output: ' + e.message;
  report = {
    top10_recommendations: [],
    tier_summaries: { tier1: '', tier2: '', tier3: '' },
    skills_i_have: [],
    skills_im_missing: [],
    gap_closing_plan: []
  };
}

const now = new Date();
const pad = n => String(n).padStart(2, '0');
const dateStr = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`;
const timeStr = `${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;
const fileBase = `skill-report-${dateStr}-${timeStr}`;

const tierTitleList = (bucket) => (bucket || []).map(t =>
  `- **${t.name}** (count ${t.count}): ${t.sample_titles.join(' | ')}`
).join('\n');

const recList = (report.top10_recommendations || []).map((r, i) =>
  `### ${i + 1}. ${r.skill}\n\n**Why it matters:** ${r.why_it_matters}\n\n**How to acquire:** ${r.how_to_acquire}\n`
).join('\n');

const gapList = (report.gap_closing_plan || []).map((g, i) =>
  `${i + 1}. **${g.skill}** — \`${(g.priority || 'medium').toUpperCase()}\` priority\n   - **Reason:** ${g.reason}\n   - **Start this week:** ${g.first_step}`
).join('\n\n');

const topTable = agg.top10.map((s, i) =>
  `| ${i + 1} | ${s.name} | ${s.count} | ${s.weighted} | ${s.tiers[1]} | ${s.tiers[2]} | ${s.tiers[3]} |`
).join('\n');

const markdown = `# Skill Demand Report\n\n**Generated:** ${now.toISOString()}\n**Jobs analyzed:** ${agg.total_jobs_analyzed}\n**Jobs with extraction errors:** ${agg.total_jobs_errored}\n**Unique skills found:** ${agg.total_skills_unique}\n${parseError ? `\n> ⚠️ Final-analysis parse warning: ${parseError}\n` : ''}\n## Top 10 In-Demand Skills\n\n| Rank | Skill | Mentions | Weighted | Tier 1 | Tier 2 | Tier 3 |\n|------|-------|----------|----------|--------|--------|--------|\n${topTable}\n\n## Recommendations: How to Acquire the Top 10\n\n${recList || '_(none returned)_'}\n\n## Skill Tiers — What the Market Wants\n\n### Tier 1 — Core (must-have)\n\n${report.tier_summaries?.tier1 || ''}\n\nRepresentative job titles requiring Tier 1 skills:\n${tierTitleList(agg.tierBuckets[1]) || '_(none)_'}\n\n### Tier 2 — Strong (less common but valuable)\n\n${report.tier_summaries?.tier2 || ''}\n\nRepresentative job titles:\n${tierTitleList(agg.tierBuckets[2]) || '_(none)_'}\n\n### Tier 3 — Edge (differentiators)\n\n${report.tier_summaries?.tier3 || ''}\n\nRepresentative job titles:\n${tierTitleList(agg.tierBuckets[3]) || '_(none)_'}\n\n## Resume Gap Analysis\n\n### Skills you HAVE (matching market demand)\n\n${(report.skills_i_have || []).map(s => `- ${s}`).join('\n') || '_(none identified)_'}\n\n### Skills you're MISSING\n\n${(report.skills_im_missing || []).map(s => `- ${s}`).join('\n') || '_(none identified)_'}\n\n### Gap-Closing Plan (prioritized by market demand × tier)\n\n${gapList || '_(no recommendations returned)_'}\n\n---\n\n_Generated by skill_extraction n8n workflow_\n`;

const rawJson = JSON.stringify({
  generated_at: now.toISOString(),
  total_jobs_analyzed: agg.total_jobs_analyzed,
  total_jobs_errored: agg.total_jobs_errored,
  total_skills_unique: agg.total_skills_unique,
  top10: agg.top10,
  tierBuckets: agg.tierBuckets,
  fullRanking: agg.fullRanking,
  analysis: report
}, null, 2);

const dirSep = (cfg.outputDir || '').includes('\\') ? '\\' : '/';
const basePath = (cfg.outputDir || 'output/skill-reports').replace(/[\\/]+$/, '') + dirSep + fileBase;

return {
  json: {
    fileBase,
    markdownPath: basePath + '.md',
    jsonPath: basePath + '.json',
    parseError,
    summary: {
      jobs: agg.total_jobs_analyzed,
      uniqueSkills: agg.total_skills_unique,
      top10: agg.top10.map(s => s.name)
    }
  },
  binary: {
    markdown: {
      data: Buffer.from(markdown, 'utf8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: fileBase + '.md',
      fileExtension: 'md'
    },
    rawJson: {
      data: Buffer.from(rawJson, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: fileBase + '.json',
      fileExtension: 'json'
    }
  }
};
